#include<bits/stdc++.h>
using namespace std;
vector<long long> a[100010],h[100010],l[100010];
map<long long,long long> mp;
long long id[1000010],cnt=1;
long long v[100010],s[1000010];
long long n,m,k;
long long lowbit(long long x)
{
	return x&-x;
}
void clear()
{
	cnt++;
}
void add(long long x,long long v)
{
	x++;
	for(long long i=x;i<=k+1;i+=lowbit(i))
	{
		if(id[i]!=cnt)
		{
			id[i]=cnt;
			s[i]=0;
		}
		s[i]+=v;
	}
}
long long query(long long x)
{
	x++;
	long long ans=0;
	for(long long i=x;i>=1;i-=lowbit(i))
	{
		if(id[i]!=cnt)
		{
			id[i]=cnt;
			s[i]=0;
		}
		ans+=s[i];
	}
	return ans;
}
int main()
{
	set<long long> s;
	scanf("%lld%lld",&n,&m);
	for(long long i=1;i<=n;i++)
	{
		scanf("%lld",&v[i]);
		s.insert(v[i]);
	}
	for(long long i=1;i<=m;i++)
	{
		long long c;
		scanf("%lld",&c);
		while(c--)
		{
			long long x;
			scanf("%lld",&x);
			a[i].push_back(x);
			s.insert(x);
			h[i].push_back(0);
			l[i].push_back(0);
		}
	}
	k=0;
	for(long long i:s)
	{
		mp[i]=++k;
	}
	for(long long i=1;i<=n;i++)
	{
		v[i]=mp[v[i]];
	}
	for(long long i=1;i<=m;i++)
	{
		for(long long &j:a[i])
		{
			j=mp[j];
		}
	}
	long long ans=0;
	for(long long i=1;i<=n;i++)
	{
//		printf("v[%lld]=%lld\n",i,v[i]);
		add(v[i],1);
		ans+=query(k)-query(v[i]);
	}
	sort(v+1,v+1+n);
	for(long long i=1;i<=m;i++)
	{
		for(long long j=0;j<a[i].size();j++)
		{
			h[i][j]=query(k)-query(a[i][j]);
			l[i][j]=query(a[i][j]-1);
			if(j)
			{
				l[i][j]+=l[i][j-1];
			}
		}
		for(long long j=(long long)(a[i].size())-2;j>=0;j--)
		{
			h[i][j]+=h[i][j+1];
		}
//		for(long long j=0;j<a[i].size();j++)
//		{
//			printf("a[%lld][%lld]=%lld h[%lld][%lld]=%lld l[%lld][%lld]=%lld\n",i,j,a[i][j],i,j,h[i][j],i,j,l[i][j]);
//		}
	}
	for(long long i=1;i<=m;i++)
	{
		clear();
		long long sum=0;
		for(long long j:a[i])
		{
			add(j,1);
			sum+=query(k)-query(j);
		}
		long long min1=h[i][0];
		for(long long j=0;j<a[i].size();j++)
		{
			long long H=l[i][j];
			long long L=(j==(long long)(a[i].size())-1?0:h[i][j+1]);
			min1=min(min1,H+L);
		}
		printf("%lld\n",ans+min1+sum);
	}
	return 0;
}
